targets.expr:
histogram_quantile(
  0.99,
  sum by (le, path) (
    rate(starlette_request_duration_seconds_bucket{instance=~"$worker_node"}[1m])
  )
)
or on (path)
(
  0 * sum by (path) (starlette_requests_total{instance=~"$worker_node"})
)

histogram_quantile(
  0.95,
  sum by (le, path) (
    rate(starlette_request_duration_seconds_bucket{instance=~"$worker_node"}[1m])
  )
)
or on (path)
(
  0 * sum by (path) (starlette_requests_total{instance=~"$worker_node"})
)

